// subdivideToFactor repeatedly halves remaining checkpoints until at
// least targetCount checkpoints are produced or no further split is
// possible (gaps reached 1 commit). Each call to subdivideCheckpoints
// doubles the count, so this rounds targetCount up to the next power
// of two. Returns the input unchanged when no further split helps.
func subdivideToFactor(
	chain []plumbing.Hash,
	current plumbing.Hash,
	remaining []plumbing.Hash,
	targetCount int,
) []plumbing.Hash {
	expanded := remaining
	for len(expanded) < targetCount {
		next := subdivideCheckpoints(chain, current, expanded)
		if len(next) <= len(expanded) {
			break
		}
		expanded = next
	}
	return expanded
}

