// observedSubdivisionFactor estimates how many sub-packs a rejected push
// should be split into based on bytes actually transmitted before the
// server cut us off. The 2× safety multiplier accounts for the fact
// that the rejected pack's full size is unknown (we observe a lower
// bound — sent bytes — not the true total). Returns 2 (the legacy
// halving behaviour) when no useful signal is available.
func observedSubdivisionFactor(sentBytes, limit int64) int {
	if sentBytes <= 0 || limit <= 0 {
		return 2
	}
	const safetyMultiplier = 2
	factor := int((sentBytes*safetyMultiplier + limit - 1) / limit)
	if factor < 2 {
		factor = 2
	}
	return factor
}

