104	func NewScanner(rs io.Reader, opts ...ScannerOption) *Scanner {
105		crc := crc32.NewIEEE()
106		packhash := gogithash.New(crypto.SHA1)
107	
108		r := &Scanner{
109			objIndex: -1,
110			hasher:   plumbing.NewHasher(format.SHA1, plumbing.AnyObject, 0),
111			crc:      crc,
112			packhash: packhash,
113			nextFn:   packHeaderSignature,
114			// Set the default size, which can be overridden by opts.
115			objectIDSize: packhash.Size(),
116		}
117	
118		for _, opt := range opts {
119			opt(r)
120		}
121	
122		r.scannerReader = newScannerReader(rs, io.MultiWriter(crc, r.packhash), r.rbuf)
123	
124		return r
125	}
