147	func (r *Scanner) Scan() bool {
148		r.m.Lock()
149		defer r.m.Unlock()
150	
151		if r.err != nil || r.nextFn == nil {
152			return false
153		}
154	
155		if err := scan(r); err != nil {
156			if errors.Is(err, io.EOF) || errors.Is(err, io.ErrUnexpectedEOF) {
157				err = fmt.Errorf("%w: %w", ErrMalformedPackfile, err)
158			}
159	
160			r.err = err
161			return false
162		}
163	
164		return true
165	}
