167	// Reset resets the current scanner, enabling it to be used to scan the
168	// same Packfile again.
169	func (r *Scanner) Reset() error {
170		if err := r.Flush(); err != nil {
171			return err
172		}
173		if _, err := r.Seek(0, io.SeekStart); err != nil {
174			return err
175		}
176		r.packhash.Reset()
177	
178		r.objIndex = -1
179		r.version = 0
180		r.objects = 0
181		r.packData = PackData{}
182		r.err = nil
183		r.nextFn = packHeaderSignature
184		return nil
185	}
